from flask import Flask, request
import logging
from pythonjsonlogger import jsonlogger

app = Flask(__name__)

logHandler = logging.StreamHandler()
formatter = jsonlogger.JsonFormatter('%(asctime)s %(levelname)s in %(module)s: %(message)s')
logHandler.setFormatter(formatter)
app.logger.addHandler(logHandler)
app.logger.setLevel(logging.INFO)

@app.before_request
def log_before_request():
    app.logger.info('Request Info', extra={
        'headers': request.headers,
        'body': request.get_json(),
    })

@app.after_request
def log_after_request(response):
    app.logger.info('Response Info', extra={
        'status': response.status_code,
        'response': response.get_data().decode("utf-8") 
    })
    return response

@app.errorhandler(500)
def handle_internal_error(error):
    app.logger.error('Server Error: %s', (error), extra={
        'status': 500,
        'type': type(error).__name__,
        'traceback': error,
    })
    return 'Internal Server Error', 500
    
@app.route('/')
def home():
    return "Hello, World!"

if __name__ == '__main__':
    app.run(host='0.0.0.0', port=8080)